index 76234ccfdcff..e1dba8c52aa2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2031,6 +2032,31 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
   }

+  // sub C1, (and (sub nuw C2, X), C3)
+  // If C3 is a negative power of 2 and C2 - C1 == ~C3, transform to:
+  // and X, (C1 | ((C2 - C1) * -C3))
+  {
+    Value *AndOp, *X;
+    const APInt *C1, *C2, *C3;
+    if (match(Op0, m_APInt(C1)) &&
+        match(Op1, m_OneUse(m_c_And(m_OneUse(m_Value(AndOp)), m_APInt(C3))))) {
+      BinaryOperator *BO = dyn_cast<BinaryOperator>(AndOp);
+      if (BO && BO->getOpcode() == Instruction::Sub && BO->hasNoUnsignedWrap() &&
+          match(AndOp, m_Sub(m_APInt(C2), m_Value(X)))) {
+        // Check if C3 is a negative power of 2
+        if (C3->isNegative() && C3->abs().isPowerOf2()) {
+          APInt NegC3 = -(*C3);  // This is 2^k
+          // Check if C2 - C1 == NegC3 - 1 (which is ~C3)
+          APInt Diff = *C2 - *C1;
+          if (Diff == NegC3 - 1) {
+            APInt NewC = *C1 | (Diff * NegC3);
+            return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), NewC));
+          }
+        }
+      }
+    }
+  }
+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
@@ -2301,6 +2327,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

